import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct ModelIntent: AppIntent {
    static var title: LocalizedStringResource = "3D Model"
    @Parameter(title: "Model Name") var modelName: String
}

struct ModelWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "ModelWidget",
            intent: ModelIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.modelName) {
                    content.add(model)
                }
            }
        }
    }
}

