struct HighlightedListView: View {
    @State private var selected: Int?
    var body: some View {
        FocusedContent(selected: $selected) {
            ForEach(0..<5) { i in
                Text("Item \(i)")
                    .background(selected == i ? Color.blue : Color.clear)
            }
        }
    }
}

